apt install postgresql
systemctl start postgresql

# connect as postgres system user
sudo -u postgres psql

# connect to specific database
psql -u postgres -d dbname
psql -h 10.10.10.1 -u postgres -d postgres -p 5432

# .pgpass file (auto-credentials): hostname:port:database:username:password
echo '10.10.10.1:5432:postgres:postgres:password' >> ~/.pgpass
chmod 600 ~/.pgpass essential psql commands -- meta commands (psql-specific, not sql)
\l                  -- list databases
\c dbname           -- connect to database
\dt                 -- list tables
\d tablename        -- describe table
\du                 -- list users/roles
\dn                 -- list schemas
\df                 -- list functions
\dp                 -- list table permissions
\i file.sql         -- execute sql file
\! command          -- run shell command
\q                  -- quit

-- sql queries
select version();
select current_user;
select current_database();
select pg_postmaster_start_time();

-- list databases
select datname from pg_database;

-- list tables
select tablename from pg_tables where schemaname = 'public';

-- users and roles
select usename, usesuper, usecreatedb, usecreaterole, passwd from pg_shadow;
select rolname, rolsuper, rolcreaterole, rolcreatedb, rolcanlogin from pg_roles;

-- check current privileges
\dp tablename
select * from information_schema.role_table_grants where grantee = current_user; postgresql authentication — pg_hba.conf # /etc/postgresql/15/main/pg_hba.conf
# controls who can connect and how

# type  database  user  address    method
