  host    all     all    127.0.0.1/32  md5    # tcp from localhost
  host    all     all    0.0.0.0/0     md5    # tcp from anywhere (risky)
  host    all     all    0.0.0.0/0     trust  # no password — critical finding red team: postgresql enumeration nmap -sv -p 5432 target
